//                                                                                 |//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include<bits/stdc++.h>using namespace std;int main(){    ios_base::sync_with_stdio(0);    cin.tie(0);    int test;    cin >> test;    while(test--){        int n , k;        cin >> n>>k;        vector <int> vec(n);        vector <int> vec1(n);        for(int i = 0;i<n;i++){            cin >> vec[i];            vec1[i]=vec[i];        }        bool flag = true;        if(k!=1){            cout << "YES\n";            flag = false;        }        else{            sort(vec1.begin(),vec1.end());            for(int i =0;i<n;i++){                if(vec[i]!=vec1[i]){                    cout << "NO\n";                    flag = false;                    break;                }            }        }        if(flag == true){            cout << "YES\n";                    }    }}